protected override void OnModelCreating(ModelBuilder modelBuilder)
{
    modelBuilder.Entity<Product>(entity =>
    {
        entity.ToContainer("Products");

        // EF Core 9 renamed the default discriminator from "Discriminator" to "$type".
        // Preserve the old name so existing 500K documents remain readable and
        // direct SQL queries filtering on c.Discriminator continue to work.
        entity.HasDiscriminator<string>("Discriminator");

        // EF Core 9 changed id generation from "EntityType|Key" to just "Key".
        // Preserve the old format so existing documents with ids like "Product|123"
        // are still found by FindAsync and point-reads.
        entity.HasRootDiscriminatorInJsonId(true);
    });

    // REMOVED: HasIndex(p => p.Sku)
    // EF Core 9 Cosmos provider throws InvalidOperationException for HasIndex calls.
    // Cosmos DB indexing is managed via the container's indexing policy
    // (Azure Portal, Bicep, or Terraform), not through EF Core.
}

